import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_node = None
    best_total_time = float('inf')

    closest_customer_distance = float('inf')
    for customer_pos in unvisited_customers:
        distance_from_depot = np.linalg.norm(customer_pos - depot_pos)
        if distance_from_depot < closest_customer_distance:
            closest_customer_distance = distance_from_depot

    for idx, customer_pos in enumerate(unvisited_customers):
        distance_to_customer = np.linalg.norm(customer_pos - cur_truck_pos)
        arrival_time = current_time + distance_to_customer / truck_speed

        wait_time = closest_customer_distance - distance_to_customer if closest_customer_distance > distance_to_customer else 0

        if time_windows[idx][0] <= arrival_time <= time_windows[idx][1]:
            total_time = arrival_time
        elif arrival_time < time_windows[idx][0]:
            total_time = time_windows[idx][0] + wait_time
        else:
            total_time = arrival_time + wait_time

        if total_time < best_total_time:
            best_total_time = total_time
            best_node = idx

    return best_node
